export default {
  async fetch(req) {
    const url = new URL(req.url);

    if (url.pathname.startsWith("/api/")) {
      return fetch(req);  // 透傳到 origin
    }

    // 修改 response
    const res = await fetch(req);
    const newRes = new Response(res.body, res);
    newRes.headers.set("X-Custom", "value");
    return newRes;
  }
};

export default {
  async fetch(req: Request): Promise<Response> {
    const url = new URL(req.url);

    // 邊緣 routing
    if (url.pathname.startsWith("/api/")) {
      return fetch(`https://api-origin.com${url.pathname}`);
    }

    return fetch(req);  // 預設 origin
  }
};
